// ── 6. Themes ────────────────────────────────────────────────────────────────
const themes: Question[] = [
  q(id('th'), T.themes, FW.analysis, 'medium', 2024, 1, m('The "theme" of a literary work is —'),
    [m('Its central idea or underlying message'), m('Its sequence of events'), m('Its list of characters'), m('Its number of pages')],
    m('Theme is the central insight or underlying message a work explores about life or human nature, such as love, justice or loss. It is distinct from plot, which is the sequence of events that conveys it.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2023, 1, m('How does theme differ from subject?'),
    [m('Subject is what a work is about; theme is what it says about that subject'), m('They are identical'), m('Theme is the page count'), m('Subject is the rhyme scheme')],
    m('The subject is the topic (e.g. "war"); the theme is the statement or insight the work makes about it (e.g. "war destroys innocence"). Theme interprets the subject rather than merely naming it.')),
  q(id('th'), T.themes, FW.analysis, 'hard', 2022, 1, m('A theme is best identified by —'),
    [m('Considering what the work as a whole suggests about life'), m('Reading only the first line'), m('Counting the characters'), m('Looking at the cover')],
    m('A theme emerges from the work as a whole — its events, characters, conflicts and imagery taken together — so it is found by reflecting on what the entire text implies, not from any single isolated detail.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2024, 1, m('A "motif" is —'),
    [m('A recurring image, idea or symbol that supports a theme'), m('The single main character'), m('The final chapter'), m('The author’s signature')],
    m('A motif is a recurring element — an image, phrase, object or idea — that appears throughout a work and, through repetition, reinforces and develops its themes, such as recurring darkness suggesting evil.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2023, 1, m('Which is a statement of theme rather than a topic?'),
    [m('"Ambition unchecked can destroy the self"'), m('"Ambition"'), m('"A Scottish king"'), m('"Set in the 11th century"')],
    m('A theme is expressed as a complete idea or claim about life, like "ambition unchecked can destroy the self". Single words like "ambition" name a topic; the others are merely facts of setting or character.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2022, 1, m('Themes are usually conveyed —'),
    [m('Indirectly, through character, plot and symbol'), m('Only by a direct statement on page one'), m('By the page numbers'), m('Through the font choice')],
    m('Most writers convey theme implicitly, letting it emerge from the interplay of character, plot, conflict, symbol and imagery, so that readers infer the message rather than being told it outright.')),
  q(id('th'), T.themes, FW.analysis, 'hard', 2024, 1, m('A "universal theme" is one that —'),
    [m('Resonates across cultures and time periods'), m('Applies to only one reader'), m('Concerns only the plot’s setting'), m('Has no meaning')],
    m('A universal theme addresses experiences common to humanity — love, death, justice, the loss of innocence — and so speaks to readers across different cultures and eras, accounting for a work’s lasting power.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2023, 1, m('A work may have —'),
    [m('More than one theme working together'), m('Only ever a single theme'), m('No relation to ideas'), m('Themes only in poetry')],
    m('Rich literary works often explore several interrelated themes at once — for example, love, ambition and mortality — which interact and deepen one another rather than being limited to one message.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2022, 1, m('The theme of "the loss of innocence" often involves —'),
    [m('A character’s movement from naivety to harsh experience'), m('A purely happy childhood with no change'), m('A list of dates'), m('A description of weather only')],
    m('This common theme traces a character’s passage from innocence or naivety to a more painful, mature awareness of the world, often triggered by a confronting experience that cannot be undone.')),
  q(id('th'), T.themes, FW.analysis, 'hard', 2024, 1, m('Imagery and symbolism contribute to theme by —'),
    [m('Reinforcing abstract ideas through concrete detail'), m('Replacing the plot entirely'), m('Listing facts'), m('Ignoring meaning')],
    m('Recurring images and symbols give concrete, sensory form to a work’s abstract concerns, so that a pattern of, say, light and dark can quietly develop and reinforce a theme such as knowledge versus ignorance.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2023, 1, m('A "didactic" work is one that —'),
    [m('Aims primarily to teach a moral or lesson'), m('Has no purpose'), m('Avoids all ideas'), m('Is purely decorative')],
    m('A didactic work is designed chiefly to instruct, conveying a moral, political or religious lesson. While it foregrounds its message, critics debate whether heavy didacticism can weaken artistic subtlety.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2022, 1, m('"Man versus nature" is best described as a —'),
    [m('Type of conflict that can generate theme'), m('Rhyme scheme'), m('Stage direction'), m('Type of metre')],
    m('"Man versus nature" is a category of conflict in which characters struggle against natural forces. Such conflicts frequently give rise to themes about human vulnerability, endurance or hubris.')),
  q(id('th'), T.themes, FW.analysis, 'hard', 2024, 1, m('To support a claim about theme, a reader should —'),
    [m('Cite specific evidence from the text'), m('Rely only on personal opinion'), m('Quote the back cover'), m('Count the chapters')],
    m('A sound interpretation of theme is grounded in textual evidence — quotations, events, imagery and character behaviour — that demonstrates how the work develops the idea, rather than unsupported assertion.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2023, 1, m('The theme of "appearance versus reality" explores —'),
    [m('The gap between how things seem and how they are'), m('Only physical descriptions'), m('The book’s length'), m('Nothing of substance')],
    m('This theme probes the difference between surface appearances and underlying truth — deceptive characters, illusions or false impressions — inviting readers to question what can be trusted.')),
  q(id('th'), T.themes, FW.analysis, 'medium', 2022, 1, m('A theme is most convincing when it is —'),
    [m('Drawn from the whole text and supported throughout'), m('Based on one stray word'), m('Imposed against the evidence'), m('Taken from the title alone')],
    m('A persuasive reading of theme is one consistently borne out across the text — recurring in events, characters, symbols and language — rather than resting on an isolated detail or contradicting the evidence.')),
]

